14	
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const k = cellKey(neighbor);
19	      const entry = neighborCounts.get(k);
20	      if (entry) {
21	        entry.count += 1;
22	      } else {
23	        neighborCounts.set(k, { cell: neighbor, count: 1 });
24	      }
25	    }
26	  }
27	
28	  const survives = (k: string, count: number): boolean =>
29	    count === 3 || (count === 2 && liveKeys.has(k));
30	
31	  const result: Cell[] = [];
32	  for (const [k, { cell, count }] of neighborCounts) {
33	    if (survives(k, count)) result.push(cell);
