1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only one neighbor (underpopulation)", () => {
12	    // Two adjacent cells - each has only 1 neighbor, both die
13	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
14	  });
15	  it("should keep alive a cell with 2 or 3 neighbors (survival)", () => {
16	    // 2x2 block - each cell has exactly 3 neighbors, all survive
17	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
18	    expect(result.sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]].sort());
19	  });
20	  it("should kill a cell with more than 3 neighbors (overpopulation)", () => {
21	    // Center cell (1,1) has 4 live neighbors in this pattern:
22	    // ###
23	    // .#.
24	    // ###
25	    const input: [number, number][] = [
26	      [0, 0], [1, 0], [2, 0],
27	              [1, 1],
28	      [0, 2], [1, 2], [2, 2],
29	    ];
30	    const result = nextGeneration(input);
31	    expect(result).not.toContainEqual([1, 1]);
32	  });
33	  it("should bring a dead cell to life with exactly 3 neighbors (reproduction)", () => {
34	    // L-shape: dead cell (1,1) has exactly 3 live neighbors → becomes alive
35	    // ##.
36	    // #..
37	    // ...
38	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
39	    const result = nextGeneration(input);
40	    expect(result).toContainEqual([1, 1]);
41	  });
42	  it("should handle the blinker oscillator pattern", () => {
43	    // Vertical blinker rotates to horizontal
44	    const gen0: [number, number][] = [[0, 0], [0, 1], [0, 2]];
45	    const result = nextGeneration(gen0);
46	    const sorted = result.map(([x, y]) => `${x},${y}`).sort();
47	    const expected = [[-1, 1], [0, 1], [1, 1]].map(([x, y]) => `${x},${y}`).sort();
48	    expect(sorted).toEqual(expected);
49	  });
