export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveKeys = new Set(liveCells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor);
      const entry = neighborCounts.get(k);
      if (entry) {
        entry.count += 1;
      } else {
        neighborCounts.set(k, { cell: neighbor, count: 1 });
      }
    }
  }

  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && liveKeys.has(k));

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (survives(k, count)) result.push(cell);
  }
  return result;
}

